export enum AppState {
  IDLE = 'IDLE', // Listening for wake word
  CONNECTING = 'CONNECTING',
  ACTIVE = 'ACTIVE', // Connected to Gemini
  ERROR = 'ERROR'
}

export enum EyeState {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING', // User is speaking (Rainbow)
  SPEAKING = 'SPEAKING', // AI is speaking (Blue)
  THINKING = 'THINKING', // Processing (maybe Pulse)
}

export interface AudioConfig {
  sampleRate: number;
}

import { Blob } from '@google/genai';

export const PCM_SAMPLE_RATE = 16000;
export const OUTPUT_SAMPLE_RATE = 24000;

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values
    let s = Math.max(-1, Math.min(1, data[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = OUTPUT_SAMPLE_RATE,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export class WakeWordDetector {
  recognition: any;
  isListening: boolean = false;
  onWake: () => void;

  constructor(onWake: () => void) {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      console.warn("Speech Recognition not supported in this browser.");
      return;
    }
    this.recognition = new SpeechRecognition();
    this.recognition.continuous = true;
    this.recognition.interimResults = false;
    this.recognition.lang = 'en-US';
    this.onWake = onWake;

    this.recognition.onresult = (event: any) => {
      for (let i = event.resultIndex; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          const transcript = event.results[i][0].transcript.trim().toLowerCase();
          console.log("Wake Word Listener heard:", transcript);
          // Simple keyword spotting with loose matching
          if (transcript.includes("airo") || 
              transcript.includes("arrow") || 
              transcript.includes("hey row") ||
              transcript.includes("hello") ||
              transcript.includes("hey airo")) {
             this.onWake();
          }
        }
      }
    };

    this.recognition.onend = () => {
        if (this.isListening) {
            try {
              this.recognition.start();
            } catch (e) {
              console.log("Re-starting recognition failed", e);
            }
        }
    };

    this.recognition.onerror = (event: any) => {
        console.error("Wake word error", event.error);
    };
  }

  start() {
    if (!this.recognition) return;
    this.isListening = true;
    try {
        this.recognition.start();
    } catch(e) { 
        // Already started?
    }
  }

  stop() {
    if (!this.recognition) return;
    this.isListening = false;
    try {
        this.recognition.stop();
    } catch(e) {}
  }
}

import React, { useEffect, useState } from 'react';
import { EyeState } from '../types';

export const Eyes = ({ state }: { state: EyeState }) => {
  const [blink, setBlink] = useState(false);
  const [lookOffset, setLookOffset] = useState({ x: 0, y: 0 });

  useEffect(() => {
    // Blink loop
    const blinkInterval = setInterval(() => {
        setBlink(true);
        setTimeout(() => setBlink(false), 200);
    }, 3000 + Math.random() * 4000);

    // Look around loop
    const lookInterval = setInterval(() => {
        if (state === EyeState.IDLE || state === EyeState.LISTENING) {
            // Random movement within a range
            const x = (Math.random() - 0.5) * 60; 
            const y = (Math.random() - 0.5) * 30; 
            setLookOffset({ x, y });
        } else if (state === EyeState.SPEAKING) {
             // Look center when speaking usually
             setLookOffset({ x: 0, y: 0 });
        }
    }, 2000 + Math.random() * 3000);

    return () => {
        clearInterval(blinkInterval);
        clearInterval(lookInterval);
    }
  }, [state]);

  const getEyeColorClass = () => {
      if (state === EyeState.LISTENING) return 'rainbow-bg border-none';
      if (state === EyeState.SPEAKING) return 'bg-blue-500 shadow-[0_0_40px_#3b82f6] border-none';
      return 'bg-white shadow-[0_0_20px_#fff]';
  };

  const getScale = () => {
      if (state === EyeState.LISTENING) return 1.3;
      if (state === EyeState.SPEAKING) return 1.1;
      return 1;
  }

  const eyeStyle = {
      transform: `translate(${lookOffset.x}px, ${lookOffset.y}px) scaleY(${blink ? 0.05 : 1}) scale(${getScale()})`,
      transition: 'transform 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94), background-color 0.5s ease',
  };

  return (
    <div className="flex gap-12 justify-center items-center h-screen w-screen bg-black overflow-hidden relative">
        {/* Helper text for user feedback */}
        <div className="absolute top-4 text-gray-800 text-xs font-mono select-none opacity-20">
            {state === EyeState.IDLE && "Say 'Hey Airo'"}
            {state === EyeState.LISTENING && "Listening..."}
            {state === EyeState.SPEAKING && "Speaking..."}
        </div>
      <div className={`w-32 h-32 rounded-full ${getEyeColorClass()}`} style={eyeStyle}></div>
      <div className={`w-32 h-32 rounded-full ${getEyeColorClass()}`} style={eyeStyle}></div>
    </div>
  );
};

import { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState } from '../types';

export const useGeminiLive = (apiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Volume meter for VAD
  const processVolume = (inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);
      // Simple threshold
      if (rms > 0.02) {
          setIsUserSpeaking(true);
          // Debounce turning it off
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
          (window as any).vadTimeout = setTimeout(() => setIsUserSpeaking(false), 500);
      }
  };

  const connect = async () => {
    if (!apiKey) return;

    try {
      setConnectionState(AppState.CONNECTING);

      const ai = new GoogleGenAI({ apiKey });

      // Setup Audio
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: PCM_SAMPLE_RATE });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Connected');
            setConnectionState(AppState.ACTIVE);

            // Start Microphone Stream
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            processorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              processVolume(inputData);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session: any) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              // Sync time
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(
                decode(base64Audio),
                ctx,
                24000,
                1
              );

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              source.onstart = () => setIsAiSpeaking(true);
              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) {
                      setIsAiSpeaking(false);
                  }
              };

              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            if (message.serverContent?.interrupted) {
                // Clear queue
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
            }
          },
          onclose: () => {
              setConnectionState(AppState.IDLE);
              onDisconnect();
          },
          onerror: (err) => {
              console.error(err);
              setConnectionState(AppState.ERROR);
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            systemInstruction: "You are Airo, a helpful and friendly voice assistant. Keep responses concise and conversational.",
        }
      });

      sessionRef.current = sessionPromise;

    } catch (e) {
      console.error("Connection failed", e);
      setConnectionState(AppState.ERROR);
    }
  };

  const disconnect = () => {
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
      }
      if (processorRef.current) {
          processorRef.current.disconnect();
      }
      if (inputContextRef.current) {
          inputContextRef.current.close();
      }
      if (audioContextRef.current) {
          audioContextRef.current.close();
      }
      // Note: session.close() not explicitly available on the promise wrapper in all versions, 
      // but breaking the websocket via stream close or reloading works. 
      // Ideally we would save the session object.
      setConnectionState(AppState.IDLE);
      onDisconnect();
  };

  return { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); // True if wake word detected
  const wakeWordRef = useRef<WakeWordDetector | null>(null);

  // Gemini Live Hook
  const { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        // On disconnect, go back to listening for wake word
        setWakeState(false);
    }
  );

  // Initialize Wake Word Detector
  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(() => {
        setWakeState(true);
    });

    return () => {
        wakeWordRef.current?.stop();
    };
  }, []);

  // Manage State Transitions
  useEffect(() => {
    if (wakeState && connectionState === AppState.IDLE) {
        // Wake word detected, stop detector, start Gemini
        wakeWordRef.current?.stop();
        connect();
    } else if (!wakeState && hasStarted) {
        // Reset, start wake word detector
        disconnect();
        wakeWordRef.current?.start();
    }
  }, [wakeState, hasStarted]);

  // Determine Visual Eye State
  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isAiSpeaking) {
          eyeState = EyeState.SPEAKING;
      } else if (isUserSpeaking) {
          eyeState = EyeState.LISTENING;
      } else {
           // Connected but silence
           eyeState = EyeState.IDLE; 
      }
  } else if (connectionState === AppState.CONNECTING) {
      eyeState = EyeState.LISTENING; // Show listening/processing while connecting
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex items-center justify-center text-white">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
      </div>
    );
  }

  return (
    <div className="relative">
      <Eyes state={eyeState} />

      {/* Optional Debug/Status Indicator */}
      <div className="absolute bottom-4 left-0 right-0 text-center pointer-events-none">
          <span className={`inline-block w-2 h-2 rounded-full mb-1 ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_5px_#22c55e]' : 
              connectionState === AppState.CONNECTING ? 'bg-yellow-500' : 'bg-red-500'
          }`}></span>
      </div>
    </div>
  );
}

