    if (!this.recognition) return;
    this.isListening = false;
    try {
        this.recognition.stop();
    } catch(e) {}
  }
}

export class WakeWordDetector {
  recognition: any;
  isListening: boolean = false;
  onWake: () => void;

  constructor(onWake: () => void, onTranscript?: (text: string) => void) {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      console.warn("Speech Recognition not supported in this browser.");
      return;
    }
    this.recognition = new SpeechRecognition();
    this.recognition.continuous = true;
    this.recognition.interimResults = true; // Enable interim results for faster matching
    this.recognition.lang = 'en-US';
    this.onWake = onWake;

    this.recognition.onresult = (event: any) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; ++i) {
        transcript += event.results[i][0].transcript;
      }

      const lower = transcript.trim().toLowerCase();
      console.log("Wake Word Listener heard:", lower);

      if (onTranscript) {
          onTranscript(lower);
      }

      // Expanded keyword spotting
      const triggers = [
          "airo", "arrow", "aero", 
          "hey airo", "hey arrow", "hey aero",
          "hero", "harrow", "air oh",
          "hey row", "hello", "hi", "wake up", "start"
      ];

      if (triggers.some(t => lower.includes(t))) {
         this.onWake();
         // Force stop to reset the buffer and prevent double triggers
         try { this.recognition.stop(); } catch(e) {}
      }
    };

    this.recognition.onend = () => {
        if (this.isListening) {
            try {
              this.recognition.start();
            } catch (e) {
              // Ignore errors if already started
            }
        }
    };

    this.recognition.onerror = (event: any) => {
        if (event.error === 'no-speech' || event.error === 'aborted') {
            return;
        }
        console.error("Wake word error", event.error);
    };
  }

  start() {
    if (!this.recognition) return;
    this.isListening = true;
    try {
        this.recognition.start();
    } catch(e) { 
        // Already started?
    }
  }

  stop() {
    if (!this.recognition) return;
    this.isListening = false;
    try {
        this.recognition.stop();
    } catch(e) {}
  }
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); // True if wake word detected
  const [lastHeard, setLastHeard] = useState("");
  const wakeWordRef = useRef<WakeWordDetector | null>(null);

  // Gemini Live Hook
  const { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        // On disconnect, go back to listening for wake word
        setWakeState(false);
    }
  );

  // Initialize Wake Word Detector
  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(
        // On Wake
        () => {
            console.log("Wake detected!");
            setWakeState(true);
            setLastHeard("Wake Word Detected!");
        },
        // On Transcript (Debug)
        (text) => {
            setLastHeard(text);
        }
    );

    return () => {
        wakeWordRef.current?.stop();
    };
  }, []);

  // Manage State Transitions
  useEffect(() => {
    if (wakeState && connectionState === AppState.IDLE) {
        // Wake word detected, stop detector, start Gemini
        wakeWordRef.current?.stop();
        connect();
    } else if (!wakeState && hasStarted) {
        // Reset, start wake word detector
        disconnect();
        // Short delay to ensure mic is released
        setTimeout(() => wakeWordRef.current?.start(), 100);
    }
  }, [wakeState, hasStarted]);

  // Determine Visual Eye State
  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isAiSpeaking) {
          eyeState = EyeState.SPEAKING;
      } else if (isUserSpeaking) {
          eyeState = EyeState.LISTENING;
      } else {
           // Connected but silence
           eyeState = EyeState.IDLE; 
      }
  } else if (connectionState === AppState.CONNECTING) {
      eyeState = EyeState.LISTENING; // Show listening/processing while connecting
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Requires Microphone Access</p>
      </div>
    );
  }

  return (
    <div className="relative">
      <Eyes state={eyeState} />

      {/* Optional Debug/Status Indicator */}
      <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center pointer-events-none gap-2">
          {/* Status Dot */}
          <span className={`inline-block w-2 h-2 rounded-full ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_5px_#22c55e]' : 
              connectionState === AppState.CONNECTING ? 'bg-yellow-500' : 'bg-red-500'
          }`}></span>

          {/* Transcript Debugger (Visible when listening for wake word) */}
          {!wakeState && (
              <div className="text-gray-600 font-mono text-sm max-w-md text-center truncate px-4">
                  {lastHeard || "Listening..."}
              </div>
          )}
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState } from '../types';

export const useGeminiLive = (apiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Volume meter for VAD
  const processVolume = (inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);
      // Simple threshold
      if (rms > 0.02) {
          setIsUserSpeaking(true);
          // Debounce turning it off
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
          (window as any).vadTimeout = setTimeout(() => setIsUserSpeaking(false), 500);
      }
  };

  const connect = async () => {
    if (!apiKey) return;

    try {
      setConnectionState(AppState.CONNECTING);

      const ai = new GoogleGenAI({ apiKey });

      // Setup Audio
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: PCM_SAMPLE_RATE });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Connected');
            setConnectionState(AppState.ACTIVE);

            // Start Microphone Stream
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            processorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              processVolume(inputData);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session: any) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              // Sync time
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(
                decode(base64Audio),
                ctx,
                24000,
                1
              );

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              setIsAiSpeaking(true);
              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) {
                      setIsAiSpeaking(false);
                  }
              };

              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            if (message.serverContent?.interrupted) {
                // Clear queue
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
            }
          },
          onclose: () => {
              setConnectionState(AppState.IDLE);
              onDisconnect();
          },
          onerror: (err) => {
              console.error(err);
              setConnectionState(AppState.ERROR);
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            systemInstruction: "You are Airo, a helpful and friendly voice assistant. Keep responses concise and conversational.",
        }
      });

      sessionRef.current = sessionPromise;

    } catch (e) {
      console.error("Connection failed", e);
      setConnectionState(AppState.ERROR);
    }
  };

  const disconnect = () => {
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
      }
      if (processorRef.current) {
          processorRef.current.disconnect();
      }
      if (inputContextRef.current) {
          inputContextRef.current.close();
      }
      if (audioContextRef.current) {
          audioContextRef.current.close();
      }
      // Note: session.close() not explicitly available on the promise wrapper in all versions, 
      // but breaking the websocket via stream close or reloading works. 
      // Ideally we would save the session object.
      setConnectionState(AppState.IDLE);
      onDisconnect();
  };

  return { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); // True if wake word detected
  const [lastHeard, setLastHeard] = useState("");
  const wakeWordRef = useRef<WakeWordDetector | null>(null);

  // Gemini Live Hook
  const { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        // On disconnect (or error recovery), go back to listening for wake word
        setWakeState(false);
    }
  );

  // Initialize Wake Word Detector
  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(
        // On Wake
        () => {
            console.log("Wake detected!");
            setWakeState(true);
            setLastHeard("Wake Word Detected!");
        },
        // On Transcript (Debug)
        (text) => {
            setLastHeard(text);
        }
    );

    return () => {
        wakeWordRef.current?.stop();
    };
  }, []);

  // Manage State Transitions with Delays
  useEffect(() => {
    let timeoutId: any;

    if (wakeState && connectionState === AppState.IDLE) {
        // 1. Wake word detected. Stop listening.
        wakeWordRef.current?.stop();

        // 2. Wait 500ms for mic to release, then connect to Gemini
        timeoutId = setTimeout(() => {
            connect();
        }, 500);

    } else if (!wakeState && hasStarted && connectionState === AppState.IDLE) {
        // 1. Session ended. Ensure Gemini is disconnected.
        disconnect();

        // 2. Wait 500ms before restarting wake word listener
        timeoutId = setTimeout(() => {
             // Only start if we are still in the correct state
             if (!wakeState) {
                wakeWordRef.current?.start();
             }
        }, 500);
    }

    return () => clearTimeout(timeoutId);
  }, [wakeState, hasStarted, connectionState]);

  // Determine Visual Eye State
  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isAiSpeaking) {
          eyeState = EyeState.SPEAKING;
      } else if (isUserSpeaking) {
          eyeState = EyeState.LISTENING;
      } else {
           // Connected but silence
           eyeState = EyeState.IDLE; 
      }
  } else if (connectionState === AppState.CONNECTING) {
      eyeState = EyeState.LISTENING; // Show listening/processing while connecting
  } else if (connectionState === AppState.ERROR) {
      eyeState = EyeState.IDLE; // Revert to idle on error
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Requires Microphone Access</p>
      </div>
    );
  }

  return (
    <div className="relative">
      <Eyes state={eyeState} />

      {/* Optional Debug/Status Indicator */}
      <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center pointer-events-none gap-2">
          {/* Status Dot */}
          <span className={`inline-block w-2 h-2 rounded-full ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_5px_#22c55e]' : 
              connectionState === AppState.CONNECTING ? 'bg-yellow-500' : 
              connectionState === AppState.ERROR ? 'bg-red-500' : 'bg-red-900'
          }`}></span>

          {/* Transcript Debugger */}
          {!wakeState && connectionState === AppState.IDLE && (
              <div className="text-gray-600 font-mono text-sm max-w-md text-center truncate px-4">
                  {lastHeard || "Listening..."}
              </div>
          )}

          {/* Error Message */}
          {connectionState === AppState.ERROR && (
              <div className="text-red-500 font-mono text-sm">
                  Connection Error. Retrying...
              </div>
          )}
      </div>
    </div>
  );
}

