  const connectionStateRef = useRef<AppState>(AppState.IDLE);
  const inactivityTimeoutRef = useRef<any>(null);

  // Sync ref with state so callbacks see current state
  useEffect(() => {
      connectionStateRef.current = connectionState;
  }, [connectionState]);

  // Cleanup function
  const disconnect = useCallback(() => {
      console.log("Disconnecting Gemini Live...");

      // Clear inactivity timer
      if (inactivityTimeoutRef.current) {
          clearTimeout(inactivityTimeoutRef.current);
          inactivityTimeoutRef.current = null;
      }

      // Stop all audio sources
      sourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      sourcesRef.current.clear();

      // Stop mic stream
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }

      // Disconnect processor
      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }

      // Close contexts
      if (inputContextRef.current) {
          inputContextRef.current.close();
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          audioContextRef.current.close();
          audioContextRef.current = null;
      }

      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  // Volume meter for VAD and Inactivity Reset
  const processVolume = useCallback((inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);

      if (rms > 0.02) {
          setIsUserSpeaking(true);
          resetInactivityTimeout();
          // Debounce turning it off
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
          (window as any).vadTimeout = setTimeout(() => setIsUserSpeaking(false), 500);
      }
  }, []);

  const resetInactivityTimeout = useCallback(() => {
      if (inactivityTimeoutRef.current) clearTimeout(inactivityTimeoutRef.current);
      if (connectionStateRef.current === AppState.ACTIVE) {
          inactivityTimeoutRef.current = setTimeout(() => {
              console.log("Inactivity timeout - disconnecting");
              disconnect();
          }, 15000); // 15 seconds of silence -> Sleep
      }
  }, [disconnect]);

  const connect = async () => {
    if (!apiKey) {
        console.error("No API Key provided");
        setConnectionState(AppState.ERROR);
        setTimeout(onDisconnect, 2000);
        return;
