            setConnectionState(AppState.ACTIVE);
            resetInactivityTimeout();

            // Start Microphone Stream Processing
            if (!inputContextRef.current || !streamRef.current) return;

            const source = inputContextRef.current.createMediaStreamSource(streamRef.current);
            const scriptProcessor = inputContextRef.current.createScriptProcessor(4096, 1, 1);
            processorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              // Only process if connected
              if (connectionStateRef.current !== AppState.ACTIVE) return;

              const inputData = e.inputBuffer.getChannelData(0);
              processVolume(inputData);

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session: any) => {
                try {
                    // Double check state before sending
                    if (connectionStateRef.current === AppState.ACTIVE) {
                       session.sendRealtimeInput({ media: pcmBlob });
                    }
                } catch (e) {
                    console.error("Error sending audio chunk", e);
                }
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputContextRef.current.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              // Sync time
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(
                decode(base64Audio),
                ctx,
                24000,
                1
              );

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              setIsAiSpeaking(true);
              resetInactivityTimeout(); // AI speaking keeps session alive

              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) {
                      setIsAiSpeaking(false);
                      resetInactivityTimeout(); // Start counting silence after AI finishes
                  }
              };

              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
            }
          },
          onclose: () => {
              console.log("Session closed by server");
              disconnect();
          },
          onerror: (err) => {
              console.error("Gemini Live Error:", err);
              // Only trigger error state if we were actually trying to be active
              if (connectionStateRef.current === AppState.CONNECTING || connectionStateRef.current === AppState.ACTIVE) {
                  setConnectionState(AppState.ERROR);
                  setTimeout(() => {
                      disconnect();
                  }, 2000);
              }
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            systemInstruction: "You are Airo, a helpful and friendly voice assistant. Keep responses concise and conversational. If you don't hear anything for a while, just say goodbye.",
        }
      });

      sessionRef.current = sessionPromise;

    } catch (e) {
      console.error("Connection failed", e);
      setConnectionState(AppState.ERROR);
      setTimeout(disconnect, 2000);
    }
  };

  return { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState };
};

function decode(base64: string) {
