export class WakeWordDetector {
  recognition: any;
  isListening: boolean = false;
  onWake: () => void;

  constructor(onWake: () => void, onTranscript?: (text: string) => void) {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      console.warn("Speech Recognition not supported in this browser.");
      return;
    }
    this.recognition = new SpeechRecognition();
    this.recognition.continuous = true;
    this.recognition.interimResults = true; // Enable interim results for faster matching
    this.recognition.lang = 'en-US';
    this.onWake = onWake;

    this.recognition.onresult = (event: any) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; ++i) {
        transcript += event.results[i][0].transcript;
      }

      const lower = transcript.trim().toLowerCase();
      console.log("Wake Word Listener heard:", lower);

      if (onTranscript) {
          onTranscript(lower);
      }

      // Expanded keyword spotting
      const triggers = [
          "airo", "arrow", "aero", 
          "hey airo", "hey arrow", "hey aero",
          "hero", "harrow", "air oh",
          "hey row", "arrow"
      ];

      if (triggers.some(t => lower.includes(t))) {
         this.onWake();
         // Abort immediately to release mic
         this.stop();
      }
    };

    this.recognition.onend = () => {
        if (this.isListening) {
            try {
              this.recognition.start();
            } catch (e) {
              // Ignore errors if already started
            }
        }
    };

    this.recognition.onerror = (event: any) => {
        if (event.error === 'no-speech' || event.error === 'aborted') {
            return;
        }
        console.error("Wake word error", event.error);
    };
  }

  start() {
    if (!this.recognition) return;
    this.isListening = true;
    try {
        this.recognition.start();
    } catch(e) { 
        // Already started?
    }
  }

  stop() {
    if (!this.recognition) return;
    this.isListening = false;
    try {
        // abort() stops immediately and does not return results, freeing the mic faster than stop()
        this.recognition.abort();
    } catch(e) {}
  }
}

