import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, FunctionDeclaration, Type, Tool } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState, VisualContent } from '../types';

// Tool Definitions
const endSessionTool: FunctionDeclaration = {
  name: "end_session",
  description: "Ends the current voice session immediately. Use this when the user says goodbye, stop, or indicates they are done.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const displayImageTool: FunctionDeclaration = {
  name: "display_image",
  description: "Displays an image to the user. Use this when you want to show a diagram, photo, or visual example.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      url: { type: Type.STRING, description: "The HTTPS URL of the image to display." },
      caption: { type: Type.STRING, description: "A short title or caption for the image." }
    },
    required: ["url"]
  }
};

const renderWidgetTool: FunctionDeclaration = {
  name: "render_widget",
  description: "Renders a custom interactive widget using HTML, CSS, and JavaScript. Use this for calculators, simple games, data visualizations, or dynamic cards.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      html: { type: Type.STRING, description: "The HTML structure." },
      css: { type: Type.STRING, description: "CSS styles (do not include <style> tags)." },
      javascript: { type: Type.STRING, description: "JavaScript code (do not include <script> tags)." },
      title: { type: Type.STRING, description: "Title of the widget." }
    },
    required: ["html"]
  }
};

const tools: Tool[] = [
  { functionDeclarations: [endSessionTool, displayImageTool, renderWidgetTool] },
  { codeExecution: {} } 
