export const useGeminiLive = (apiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);
  const [visualContent, setVisualContent] = useState<VisualContent | null>(null);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const connectionStateRef = useRef<AppState>(AppState.IDLE);
  const inactivityTimeoutRef = useRef<any>(null);
  const connectionIdRef = useRef<number>(0);

  useEffect(() => {
      connectionStateRef.current = connectionState;
  }, [connectionState]);

  const cleanupAudioContexts = async () => {
      if (inputContextRef.current) {
          const ctx = inputContextRef.current;
          inputContextRef.current = null;
          try { await ctx.close(); } catch(e) {}
      }
      if (audioContextRef.current) {
          const ctx = audioContextRef.current;
          audioContextRef.current = null;
          try { await ctx.close(); } catch(e) {}
      }
  };

  const disconnect = useCallback(() => {
      console.log("Disconnecting Gemini Live...");
      connectionIdRef.current++;

      if (inactivityTimeoutRef.current) {
          clearTimeout(inactivityTimeoutRef.current);
          inactivityTimeoutRef.current = null;
      }

      sourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      sourcesRef.current.clear();

      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }

      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }

      cleanupAudioContexts();

      setVisualContent(null);
      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  const processVolume = useCallback((inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);

      if (rms > 0.02) {
          setIsUserSpeaking(true);
          resetInactivityTimeout();
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
          (window as any).vadTimeout = setTimeout(() => setIsUserSpeaking(false), 500);
      }
  }, []);

  const resetInactivityTimeout = useCallback(() => {
      if (inactivityTimeoutRef.current) clearTimeout(inactivityTimeoutRef.current);
      if (connectionStateRef.current === AppState.ACTIVE) {
          inactivityTimeoutRef.current = setTimeout(() => {
              console.log("Inactivity timeout - disconnecting");
              disconnect();
          }, 30000); 
      }
  }, [disconnect]);

  const connect = async (retryCount = 0) => {
    if (!apiKey) {
        setConnectionState(AppState.ERROR);
        setTimeout(onDisconnect, 2000);
        return;
    }

    const currentConnectionId = ++connectionIdRef.current;

    try {
      setConnectionState(AppState.CONNECTING);

      const ai = new GoogleGenAI({ apiKey });

      // Ensure previous contexts are closed before creating new ones
      await cleanupAudioContexts();

      try {
        inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: PCM_SAMPLE_RATE });
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      } catch (e) {
         console.error("Failed to create AudioContext", e);
         throw e;
      }

      // Parallel Initialization
      const streamPromise = navigator.mediaDevices.getUserMedia({ audio: true });

      streamPromise.then(stream => {
          if (currentConnectionId !== connectionIdRef.current) {
             stream.getTracks().forEach(t => t.stop());
          }
      }).catch(() => { /* Handled in onopen via await */ });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: async () => {
            if (currentConnectionId !== connectionIdRef.current) return;
            console.log('Gemini Live Connected');

            try {
                const stream = await streamPromise;
                if (currentConnectionId !== connectionIdRef.current) {
                    stream.getTracks().forEach(t => t.stop());
                    return;
                }

                streamRef.current = stream;
                setConnectionState(AppState.ACTIVE);
                resetInactivityTimeout();

                if (!inputContextRef.current) return;

                const source = inputContextRef.current.createMediaStreamSource(stream);
                const scriptProcessor = inputContextRef.current.createScriptProcessor(4096, 1, 1);
                processorRef.current = scriptProcessor;

                scriptProcessor.onaudioprocess = (e) => {
                  if (connectionStateRef.current !== AppState.ACTIVE || currentConnectionId !== connectionIdRef.current) return;

                  const inputData = e.inputBuffer.getChannelData(0);
                  processVolume(inputData);

                  const pcmBlob = createPcmBlob(inputData);
                  sessionPromise.then((session: any) => {
                    try {
                        if (connectionStateRef.current === AppState.ACTIVE && currentConnectionId === connectionIdRef.current) {
                           session.sendRealtimeInput({ media: pcmBlob });
                        }
                    } catch (e) {
                        console.error("Error sending audio chunk", e);
                    }
                  });
                };

                source.connect(scriptProcessor);
                scriptProcessor.connect(inputContextRef.current.destination);

            } catch (err) {
                console.error("Microphone failed", err);
                if (currentConnectionId === connectionIdRef.current) disconnect();
            }
          },
          onmessage: async (message: LiveServerMessage) => {
            if (currentConnectionId !== connectionIdRef.current) return;

            // Handle Audio
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              setIsAiSpeaking(true);
              resetInactivityTimeout(); 

              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) {
                      setIsAiSpeaking(false);
                      resetInactivityTimeout(); 
                  }
              };

              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            // Handle Tool Calls
            if (message.toolCall) {
                const session = await sessionPromise;
                const functionResponses: any[] = [];

                for (const fc of message.toolCall.functionCalls) {
                    let result: any = { status: "ok" };

                    if (fc.name === 'end_session') {
                        disconnect();
                        return;
                    } else if (fc.name === 'display_image') {
                        setVisualContent({
                            type: 'image',
                            content: (fc.args as any).url,
                            title: (fc.args as any).caption
                        });
                        result = { result: "Image displayed successfully" };
                    } else if (fc.name === 'render_widget') {
                        const args = fc.args as any;
                        const fullHtml = `
                          <html>
                            <style>
                                body { font-family: sans-serif; margin: 0; padding: 16px; background: white; color: black; }
                                ${args.css || ''}
                            </style>
                            <body>
                                ${args.html}
                                <script>
                                    ${args.javascript || ''}
                                </script>
                            </body>
                          </html>
                        `;
                        setVisualContent({
                            type: 'widget',
                            content: fullHtml,
                            title: args.title
                        });
                        result = { result: "Widget rendered successfully" };
                    }

                    functionResponses.push({
                        id: fc.id,
                        name: fc.name,
                        response: result
                    });
                }
                if (functionResponses.length > 0) {
                     session.sendToolResponse({ functionResponses });
                }
            }

            if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
            }
          },
          onclose: () => {
             if (currentConnectionId !== connectionIdRef.current) return;
              console.log("Session closed by server");
              disconnect();
          },
          onerror: (err) => {
              if (currentConnectionId !== connectionIdRef.current) return;
              console.error("Gemini Live Error:", err);

              // Retry logic for Network Errors
              if (retryCount === 0) {
                  console.log("Attempting retry due to error...");
                  setTimeout(() => connect(1), 500);
              } else {
                  setConnectionState(AppState.ERROR);
                  setTimeout(() => {
                      if (currentConnectionId === connectionIdRef.current) disconnect();
                  }, 2000);
              }
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            tools: tools,
            systemInstruction: `You are Airo, a helpful and friendly voice assistant. 
            - Keep responses concise and conversational.
            - If you don't hear anything for a while, just say goodbye and use the end_session tool.
            - If asked to show an image, use the display_image tool.
            - If asked to write code (like python), use the built-in code execution tool.
            - If asked to create a UI, calculator, or visual widget, use the render_widget tool with valid HTML/CSS/JS.
            - If the user says "Goodbye" or "Stop", ALWAYS use the end_session tool to close the connection.`,
        }
      });

    } catch (e) {
      if (currentConnectionId !== connectionIdRef.current) return;
      console.error("Connection failed", e);
      setConnectionState(AppState.ERROR);
      setTimeout(() => {
           if (currentConnectionId === connectionIdRef.current) disconnect();
      }, 2000);
    }
  };

  return { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState, visualContent };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { VisualDisplay } from './components/VisualDisplay';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

// Version: 1.1.0 - Added Swipe-to-dismiss and optimized connection timing
export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); // True if wake word detected
  const [lastHeard, setLastHeard] = useState("");
  const wakeWordRef = useRef<WakeWordDetector | null>(null);
  const holdTimerRef = useRef<any>(null);

  // Gemini Live Hook
  const { connect, disconnect, isAiSpeaking, isUserSpeaking, connectionState, visualContent, setVisualContent } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        setWakeState(false);
    }
  );

  // Initialize Wake Word Detector
  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(
        () => {
            setWakeState(true);
            setLastHeard("Wake Word Detected!");
        },
        (text) => {
            setLastHeard(text);
        }
    );

    return () => {
        wakeWordRef.current?.stop();
    };
  }, []);

  // Manage State Transitions
  useEffect(() => {
    let timeoutId: any;

    if (wakeState && connectionState === AppState.IDLE) {
        // 1. Stop listening immediately.
        wakeWordRef.current?.stop();

        // 2. Wait 500ms (Safer for hardware release) then connect
        timeoutId = setTimeout(() => {
            connect();
        }, 500);

    } else if (!wakeState && hasStarted && connectionState === AppState.IDLE) {
        disconnect();

        timeoutId = setTimeout(() => {
             if (!wakeState) {
                wakeWordRef.current?.start();
             }
        }, 800);
    }

    return () => clearTimeout(timeoutId);
  }, [wakeState, hasStarted, connectionState]);

  // Eye States
  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isAiSpeaking) {
          eyeState = EyeState.SPEAKING;
      } else if (isUserSpeaking) {
          eyeState = EyeState.LISTENING;
      } else {
           eyeState = EyeState.IDLE; 
      }
  } else if (connectionState === AppState.CONNECTING) {
      eyeState = EyeState.LISTENING;
  } else if (connectionState === AppState.ERROR) {
      eyeState = EyeState.IDLE;
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  const handlePointerDown = () => {
      if (!hasStarted) return;
      if (connectionState !== AppState.IDLE) return;
      holdTimerRef.current = setTimeout(() => {
          setWakeState(true);
          setLastHeard("Manual Trigger");
      }, 600);
  };

  const handlePointerUp = () => {
      if (holdTimerRef.current) {
          clearTimeout(holdTimerRef.current);
          holdTimerRef.current = null;
      }
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Requires Microphone Access</p>
      </div>
    );
  }

  return (
    <div 
        className="relative h-screen w-screen overflow-hidden select-none bg-black"
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
    >
      <Eyes state={eyeState} />

      <VisualDisplay 
        data={visualContent} 
        onDismiss={() => setVisualContent(null)} 
      />

      {/* Bottom Interface */}
      <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center pointer-events-none gap-2 z-10">
          <span className={`inline-block w-2 h-2 rounded-full transition-all duration-500 ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_10px_#22c55e]' : 
              connectionState === AppState.CONNECTING ? 'bg-yellow-500 animate-pulse' : 
              connectionState === AppState.ERROR ? 'bg-red-500' : 'bg-white/10'
          }`}></span>

          {!wakeState && connectionState === AppState.IDLE && (
              <div className="text-gray-600 font-mono text-xs uppercase tracking-widest opacity-50">
                  {lastHeard || "Awaiting 'Hey Airo'"}
              </div>
          )}

          {connectionState === AppState.ERROR && (
              <div className="text-red-500 font-mono text-xs animate-pulse">
                  System Connection Error. Retrying...
              </div>
          )}
      </div>
    </div>
  );
}

import React, { useEffect, useState, useRef } from 'react';
import { VisualContent } from '../types';

interface VisualDisplayProps {
  data: VisualContent | null;
  onDismiss: () => void;
}

export const VisualDisplay: React.FC<VisualDisplayProps> = ({ data, onDismiss }) => {
  const [offsetY, setOffsetY] = useState(0);
  const startY = useRef(0);
  const isDragging = useRef(false);
  const timerRef = useRef<any>(null);

  // Auto-dismiss after 5 seconds
  useEffect(() => {
    if (data && data.type !== 'none') {
      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => {
        onDismiss();
      }, 5000);
    }
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [data, onDismiss]);

  if (!data || data.type === 'none') return null;

  const handleTouchStart = (e: React.TouchEvent | React.MouseEvent) => {
    isDragging.current = true;
    startY.current = 'touches' in e ? e.touches[0].clientY : e.clientY;
    if (timerRef.current) clearTimeout(timerRef.current);
  };

  const handleTouchMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!isDragging.current) return;
    const currentY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const diff = currentY - startY.current;
    if (diff > 0) {
      setOffsetY(diff);
    }
  };

  const handleTouchEnd = () => {
    if (!isDragging.current) return;
    isDragging.current = false;
    if (offsetY > 150) {
      onDismiss();
    } else {
      setOffsetY(0);
      // Restart timer if not dismissed
      timerRef.current = setTimeout(() => onDismiss(), 5000);
    }
  };

  return (
    <div className="absolute inset-0 z-50 flex items-end justify-center pointer-events-none p-4 pb-12 sm:items-center sm:pb-4">
      <div 
        className="bg-gray-900/95 backdrop-blur-xl border border-gray-700/50 rounded-3xl overflow-hidden shadow-[0_20px_60px_rgba(0,0,0,0.8)] max-w-4xl w-full max-h-[85vh] flex flex-col pointer-events-auto transition-transform duration-200 ease-out animate-in slide-in-from-bottom-10 fade-in zoom-in"
        style={{ transform: `translateY(${offsetY}px)` }}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onMouseDown={handleTouchStart}
        onMouseMove={handleTouchMove}
        onMouseUp={handleTouchEnd}
        onMouseLeave={handleTouchEnd}
      >
        {/* Swipe Handle */}
        <div className="h-10 flex items-center justify-center bg-gray-800/50 cursor-grab active:cursor-grabbing">
            <div className="w-12 h-1.5 bg-gray-600 rounded-full"></div>
        </div>

        {/* Header */}
        {(data.title) && (
            <div className="px-6 py-3 border-b border-gray-700/50 flex justify-between items-center bg-gray-900/50">
                <span className="text-gray-300 font-mono text-sm tracking-tight">{data.title}</span>
                <button 
                  onClick={onDismiss}
                  className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/10 transition-colors text-gray-500 hover:text-white"
                >
                  ✕
                </button>
            </div>
        )}

        {/* Content */}
        <div className="flex-1 overflow-auto bg-black relative flex items-center justify-center min-h-[300px] sm:min-h-[400px]">
            {data.type === 'image' && (
                <img 
                    src={data.content} 
                    alt="AI Display" 
                    className="max-w-full max-h-full object-contain p-2"
                    onLoad={() => {
                        // Visual confirmation image loaded
                    }}
                />
            )}

            {data.type === 'widget' && (
                <iframe
                    title="AI Widget"
                    srcDoc={data.content}
                    className="w-full h-full border-none bg-white"
                    sandbox="allow-scripts allow-forms allow-same-origin"
                />
            )}
        </div>
      </div>
    </div>
  );
};

import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, FunctionDeclaration, Type, Tool } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState, VisualContent } from '../types';

// Tool Definitions
const endSessionTool: FunctionDeclaration = {
  name: "end_session",
  description: "Ends the current voice session immediately. Use this when the user says goodbye, stop, or indicates they are done.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const display_image: FunctionDeclaration = {
  name: "display_image",
  description: "Displays an image to the user via a URL.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      url: { type: Type.STRING, description: "The HTTPS URL of the image." },
      caption: { type: Type.STRING, description: "A title for the image." }
    },
    required: ["url"]
  }
};

const render_widget: FunctionDeclaration = {
  name: "render_widget",
  description: "Renders a custom UI widget using HTML/CSS/JS.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      html: { type: Type.STRING },
      css: { type: Type.STRING },
      javascript: { type: Type.STRING },
      title: { type: Type.STRING }
    },
    required: ["html"]
  }
};

const tools: Tool[] = [
  { functionDeclarations: [endSessionTool, display_image, render_widget] },
  { codeExecution: {} } 
];

export const useGeminiLive = (apiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);
  const [visualContent, setVisualContent] = useState<VisualContent | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const connectionStateRef = useRef<AppState>(AppState.IDLE);
  const inactivityTimeoutRef = useRef<any>(null);
  const connectionIdRef = useRef<number>(0);

  useEffect(() => {
      connectionStateRef.current = connectionState;
  }, [connectionState]);

  const cleanupAudioContexts = async () => {
      if (inputContextRef.current) {
          const ctx = inputContextRef.current;
          inputContextRef.current = null;
          try { await ctx.close(); } catch(e) {}
      }
      if (audioContextRef.current) {
          const ctx = audioContextRef.current;
          audioContextRef.current = null;
          try { await ctx.close(); } catch(e) {}
      }
  };

  const disconnect = useCallback(() => {
      console.log("Disconnecting Gemini Live...");
      connectionIdRef.current++;

      if (inactivityTimeoutRef.current) {
          clearTimeout(inactivityTimeoutRef.current);
          inactivityTimeoutRef.current = null;
      }

      sourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      sourcesRef.current.clear();

      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }

      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }

      cleanupAudioContexts();

      // We do NOT clear setVisualContent here to allow it to stay for its 5s duration
      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  const processVolume = useCallback((inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);

      if (rms > 0.02) {
          setIsUserSpeaking(true);
          resetInactivityTimeout();
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
          (window as any).vadTimeout = setTimeout(() => setIsUserSpeaking(false), 500);
      }
  }, []);

  const resetInactivityTimeout = useCallback(() => {
      if (inactivityTimeoutRef.current) clearTimeout(inactivityTimeoutRef.current);
      if (connectionStateRef.current === AppState.ACTIVE) {
          inactivityTimeoutRef.current = setTimeout(() => {
              disconnect();
          }, 30000); 
      }
  }, [disconnect]);

  const connect = async (retryCount = 0) => {
    if (!apiKey) {
        setConnectionState(AppState.ERROR);
        return;
    }

    const currentConnectionId = ++connectionIdRef.current;

    try {
      setConnectionState(AppState.CONNECTING);

      // Fresh AI instance for every connection attempt
