const endSessionTool: FunctionDeclaration = {
  name: "end_session",
  description: "Ends the current voice session immediately. Use this when the user says goodbye, stop, or indicates they are done.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const display_image: FunctionDeclaration = {
  name: "display_image",
  description: "Displays an image to the user via a URL.",
  parameters: {
    type: Type.OBJECT,
    properties: {
