      console.log("Cleaning up audio contexts...");
      if (inputContextRef.current) {
          const ctx = inputContextRef.current;
          inputContextRef.current = null;
          try { await ctx.close(); } catch(e) { console.warn(e); }
      }
      if (audioContextRef.current) {
          const ctx = audioContextRef.current;
          audioContextRef.current = null;
          try { await ctx.close(); } catch(e) { console.warn(e); }
      }
      // Brief pause to allow OS to register the close
      await new Promise(r => setTimeout(r, 100));
  };

  const disconnect = useCallback(async () => {
      console.log("Disconnecting Gemini Live...");
      connectionIdRef.current++;

      if (inactivityTimeoutRef.current) {
          clearTimeout(inactivityTimeoutRef.current);
          inactivityTimeoutRef.current = null;
      }

      sourcesRef.current.forEach(source => {
          try { source.stop(); } catch (e) {}
      });
      sourcesRef.current.clear();

      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }

      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }

      await cleanupAudioContexts();

      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  const processVolume = useCallback((inputData: Float32Array) => {
      let sum = 0;
      for (let i = 0; i < inputData.length; i++) {
          sum += inputData[i] * inputData[i];
      }
      const rms = Math.sqrt(sum / inputData.length);

      if (rms > 0.02) {
          setIsUserSpeaking(true);
          resetInactivityTimeout();
          if ((window as any).vadTimeout) clearTimeout((window as any).vadTimeout);
