                    else if (fc.name === 'close_visual') {
                        setVisualContent(null);
                        result = { result: "Visual display closed" };
                    }
                    else if (fc.name === 'render_widget') {
                        setVisualContent({ type: 'widget', content: (fc.args as any).html, title: (fc.args as any).title || 'Widget' });
                        result = { result: "Widget rendered" };
                    }
                    functionResponses.push({ id: fc.id, name: fc.name, response: result });
                }
                if (functionResponses.length > 0) session.sendToolResponse({ functionResponses });
            }

            if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => { try{s.stop()}catch(e){} });
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
                setIsThinking(false);
            }
          },
          onclose: () => { if (currentId === connectionIdRef.current) disconnect(); },
          onerror: (err) => {
              console.error("Critical Connection Error:", err);
              if (retryCount < 2) setTimeout(() => connect(retryCount + 1), 1000);
              else { setConnectionState(AppState.ERROR); setTimeout(disconnect, 2000); }
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            tools: tools,
            thinkingConfig: { thinkingBudget: 4096 },
            systemInstruction: `You are Airo, a voice assistant with vision. 
            - Use your camera to see the user and their environment.
            - Keep responses brief and conversational.
            - When you show an image using display_image, it stays visible until you call close_visual.
            - CALL close_visual once you've explained the image or the conversation has moved on.
            - If you are doing complex tasks or tool calls, your eyes turn yellow.
            - Use end_session to finish the conversation completely.`,
        }
      });
    } catch (e) {
      setConnectionState(AppState.ERROR);
      setTimeout(disconnect, 2000);
    }
  };

  return { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { VisualDisplay } from './components/VisualDisplay';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

// Version: 1.4.0 - Vision Integration & AI-Controlled Visuals
export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); 
  const [isPreparing, setIsPreparing] = useState(false);
  const [lastHeard, setLastHeard] = useState("");
  const wakeWordRef = useRef<WakeWordDetector | null>(null);
  const holdTimerRef = useRef<any>(null);

  const { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        setWakeState(false);
        setIsPreparing(false);
    }
  );

  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(
        () => {
            if (connectionState === AppState.IDLE && !isPreparing) {
                setWakeState(true);
                setLastHeard("Wake Word Detected!");
            }
        },
        (text) => setLastHeard(text)
    );
    return () => wakeWordRef.current?.stop();
  }, [connectionState, isPreparing]);

  useEffect(() => {
    let timeoutId: any;

    if (wakeState && connectionState === AppState.IDLE) {
        setIsPreparing(true);
        wakeWordRef.current?.stop();

        timeoutId = setTimeout(() => {
            if (wakeState) {
                connect().finally(() => setIsPreparing(false));
            }
        }, 1500);

    } else if (!wakeState && hasStarted && connectionState === AppState.IDLE) {
        disconnect();
        timeoutId = setTimeout(() => {
             if (!wakeState && !isPreparing) {
                wakeWordRef.current?.start();
             }
        }, 1200);
    }

    return () => clearTimeout(timeoutId);
  }, [wakeState, hasStarted, connectionState]);

  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isThinking) eyeState = EyeState.THINKING;
      else if (isAiSpeaking) eyeState = EyeState.SPEAKING;
      else eyeState = EyeState.LISTENING;
  } else if (connectionState === AppState.CONNECTING || isPreparing) {
      eyeState = EyeState.LISTENING;
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  const handlePointerDown = () => {
      if (!hasStarted || isPreparing || connectionState !== AppState.IDLE) return;
      holdTimerRef.current = setTimeout(() => {
          setWakeState(true);
          setLastHeard("Manual Hold Triggered");
      }, 700);
  };

  const handlePointerUp = () => {
      if (holdTimerRef.current) {
          clearTimeout(holdTimerRef.current);
          holdTimerRef.current = null;
      }
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Vision & Voice Active (v1.4.0)</p>
      </div>
    );
  }

  return (
    <div 
        className="relative h-screen w-screen overflow-hidden select-none bg-black"
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
    >
      <Eyes state={eyeState} />

      <VisualDisplay 
        data={visualContent} 
        onDismiss={() => setVisualContent(null)} 
      />

      <div className="absolute bottom-6 left-0 right-0 flex flex-col items-center pointer-events-none gap-3 z-10">
          <span className={`inline-block w-2.5 h-2.5 rounded-full transition-all duration-700 ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_15px_#22c55e]' : 
              connectionState === AppState.CONNECTING || isPreparing ? 'bg-yellow-500 animate-pulse' : 
              connectionState === AppState.ERROR ? 'bg-red-500' : 'bg-white/5'
          }`}></span>

          <div className="text-gray-500 font-mono text-[10px] uppercase tracking-[0.2em] opacity-60 text-center px-4 max-w-xs truncate">
              {isPreparing ? "Calibrating Sensors..." : (lastHeard || "Awaiting 'Hey Airo'")}
          </div>

          {connectionState === AppState.ERROR && (
              <div className="text-red-500 font-mono text-xs animate-pulse bg-red-900/10 px-3 py-1 rounded-full border border-red-900/20">
                  SYSTEM BUSY - RECONNECTING
              </div>
          )}
      </div>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { VisualContent } from '../types';

interface VisualDisplayProps {
  data: VisualContent | null;
  onDismiss: () => void;
}

export const VisualDisplay: React.FC<VisualDisplayProps> = ({ data, onDismiss }) => {
  const [offsetY, setOffsetY] = useState(0);
  const [hasLoaded, setHasLoaded] = useState(false);
  const startY = useRef(0);
  const isDragging = useRef(false);

  if (!data || data.type === 'none') return null;

  const handleDragStart = (e: React.TouchEvent | React.MouseEvent) => {
    isDragging.current = true;
    startY.current = 'touches' in e ? e.touches[0].clientY : e.clientY;
  };

  const handleDragMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!isDragging.current) return;
    const currentY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    const diff = currentY - startY.current;
    if (diff > 0) setOffsetY(diff);
  };

  const handleDragEnd = () => {
    if (!isDragging.current) return;
    isDragging.current = false;
    if (offsetY > 150) onDismiss();
    else setOffsetY(0);
  };

  return (
    <div className="absolute inset-0 z-50 flex items-end justify-center pointer-events-none p-4 pb-12 sm:items-center sm:pb-4">
      <div 
        className="bg-gray-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl overflow-hidden shadow-[0_20px_80px_rgba(0,0,0,0.9)] max-w-4xl w-full max-h-[80vh] flex flex-col pointer-events-auto transition-transform duration-300 ease-out animate-in slide-in-from-bottom-20 fade-in"
        style={{ transform: `translateY(${offsetY}px)` }}
        onTouchStart={handleDragStart}
        onTouchMove={handleDragMove}
        onTouchEnd={handleDragEnd}
        onMouseDown={handleDragStart}
        onMouseMove={handleDragMove}
        onMouseUp={handleDragEnd}
        onMouseLeave={handleDragEnd}
      >
        <div className="h-12 flex items-center justify-center bg-white/5 cursor-grab active:cursor-grabbing border-b border-white/5">
            <div className="w-16 h-1 bg-white/20 rounded-full"></div>
        </div>

        {data.title && (
            <div className="px-6 py-4 flex justify-between items-center">
                <span className="text-white/60 font-mono text-xs tracking-widest uppercase">{data.title}</span>
                <button onClick={onDismiss} className="text-white/30 hover:text-white transition-colors">✕</button>
            </div>
        )}

        <div className="flex-1 overflow-auto bg-black flex items-center justify-center min-h-[350px]">
            {data.type === 'image' && (
                <img 
                    src={data.content} 
                    alt="AI Visual" 
                    className="max-w-full max-h-full object-contain p-4"
                    onLoad={() => setHasLoaded(true)}
                    onError={() => onDismiss()}
                />
            )}
            {data.type === 'widget' && (
                <iframe
                    title="AI Widget"
                    srcDoc={data.content}
                    className="w-full h-full border-none bg-white"
                    onLoad={() => setHasLoaded(true)}
                />
            )}
            {!hasLoaded && (
                <div className="absolute inset-0 flex items-center justify-center bg-black">
                    <div className="w-8 h-8 border-2 border-white/20 border-t-white/80 rounded-full animate-spin"></div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

