import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, FunctionDeclaration, Type, Tool } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState, VisualContent, EyeState } from '../types';

const endSessionTool: FunctionDeclaration = {
  name: "end_session",
  description: "Ends the voice session. Use when user is done.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const display_image: FunctionDeclaration = {
  name: "display_image",
  description: "Displays an image from a URL. Must use a direct image link.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      url: { type: Type.STRING },
      caption: { type: Type.STRING }
    },
    required: ["url"]
  }
};

const close_visual: FunctionDeclaration = {
  name: "close_visual",
  description: "Closes any currently displayed image or widget.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const render_widget: FunctionDeclaration = {
  name: "render_widget",
  description: "Renders an interactive UI widget.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      html: { type: Type.STRING },
      css: { type: Type.STRING },
      javascript: { type: Type.STRING },
      title: { type: Type.STRING }
    },
    required: ["html"]
  }
};

const tools: Tool[] = [
  { functionDeclarations: [endSessionTool, display_image, render_widget, close_visual] },
  { codeExecution: {} } 
];

export const useGeminiLive = (initialApiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);
  const [visualContent, setVisualContent] = useState<VisualContent | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const connectionStateRef = useRef<AppState>(AppState.IDLE);
  const connectionIdRef = useRef<number>(0);
  const videoIntervalRef = useRef<any>(null);

  useEffect(() => { connectionStateRef.current = connectionState; }, [connectionState]);

  const cleanup = async () => {
      if (videoIntervalRef.current) clearInterval(videoIntervalRef.current);
      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }
      if (inputContextRef.current) {
          await inputContextRef.current.close().catch(() => {});
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          await audioContextRef.current.close().catch(() => {});
          audioContextRef.current = null;
      }
      await new Promise(r => setTimeout(r, 200));
  };

  const disconnect = useCallback(async () => {
      connectionIdRef.current++;
      sourcesRef.current.forEach(s => { try { s.stop(); } catch(e){} });
      sourcesRef.current.clear();
      setIsThinking(false);
      setIsAiSpeaking(false);
      await cleanup();
      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  const connect = async (retryCount = 0): Promise<void> => {
    // Always use the latest API key injected by the platform
    const currentApiKey = process.env.API_KEY || initialApiKey;
    if (!currentApiKey) return;

    const currentId = ++connectionIdRef.current;

    try {
      setConnectionState(AppState.CONNECTING);
      await cleanup();

      const ai = new GoogleGenAI({ apiKey: currentApiKey });
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: PCM_SAMPLE_RATE });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // STRICT AUDIO CONSTRAINTS to stop repeating/echoing
      const streamPromise = navigator.mediaDevices.getUserMedia({ 
          audio: {
              echoCancellation: true,
              noiseSuppression: true,
              autoGainControl: true
          },
          video: { width: { ideal: 640 }, height: { ideal: 480 }, frameRate: { ideal: 5 } }
      });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: async () => {
            if (currentId !== connectionIdRef.current) return;
            try {
                const stream = await streamPromise;
                streamRef.current = stream;
                setConnectionState(AppState.ACTIVE);

                if (!inputContextRef.current) return;
                const source = inputContextRef.current.createMediaStreamSource(stream);
                const scriptProcessor = inputContextRef.current.createScriptProcessor(4096, 1, 1);
                processorRef.current = scriptProcessor;
                scriptProcessor.onaudioprocess = (e) => {
                  if (connectionStateRef.current !== AppState.ACTIVE || currentId !== connectionIdRef.current) return;
                  const inputData = e.inputBuffer.getChannelData(0);
                  const pcmBlob = createPcmBlob(inputData);
                  sessionPromise.then((session: any) => {
                    try { session.sendRealtimeInput({ media: pcmBlob }); } catch (err) {}
                  });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputContextRef.current.destination);

                const videoEl = document.createElement('video');
                videoEl.srcObject = stream;
                videoEl.play();
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');

                videoIntervalRef.current = setInterval(() => {
                    if (connectionStateRef.current !== AppState.ACTIVE || currentId !== connectionIdRef.current) return;
                    if (ctx && videoEl.readyState >= 2) {
                        canvas.width = 320;
                        canvas.height = 240;
                        ctx.drawImage(videoEl, 0, 0, canvas.width, canvas.height);
                        const base64Data = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
                        sessionPromise.then(session => {
                            session.sendRealtimeInput({ media: { data: base64Data, mimeType: 'image/jpeg' } });
                        });
                    }
                }, 1000);

            } catch (err) { disconnect(); }
          },
          onmessage: async (message: LiveServerMessage) => {
            if (currentId !== connectionIdRef.current) return;

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              setIsAiSpeaking(true);
              setIsThinking(false);
              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            if (message.toolCall) {
                setIsThinking(true);
                const session = await sessionPromise;
                const functionResponses: any[] = [];
                for (const fc of message.toolCall.functionCalls) {
                    let result: any = { status: "ok" };
                    if (fc.name === 'end_session') { disconnect(); return; }
                    else if (fc.name === 'display_image') {
                        setVisualContent({ type: 'image', content: (fc.args as any).url, title: (fc.args as any).caption || 'Image Content' });
                        result = { result: "Image rendered" };
                    }
                    else if (fc.name === 'close_visual') {
                        setVisualContent(null);
                        result = { result: "Visual display closed" };
                    }
                    else if (fc.name === 'render_widget') {
                        setVisualContent({ type: 'widget', content: (fc.args as any).html, title: (fc.args as any).title || 'Widget' });
                        result = { result: "Widget rendered" };
                    }
                    functionResponses.push({ id: fc.id, name: fc.name, response: result });
                }
                if (functionResponses.length > 0) session.sendToolResponse({ functionResponses });
            }

            if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => { try{s.stop()}catch(e){} });
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
                setIsThinking(false);
            }
          },
          onclose: () => { if (currentId === connectionIdRef.current) disconnect(); },
          onerror: async (err: any) => {
              console.error("Connection Error Output:", err);
              // SPECIFIC FIX for Entity Not Found: Trigger key selection
              const errorStr = String(err);
              if (errorStr.includes("Requested entity was not found")) {
                  console.warn("Project key lacks permissions. Requesting re-selection...");
                  if (window.aistudio) {
                      await window.aistudio.openSelectKey();
                      // Key selection triggers a hot reload usually, but we manually retry once
                      if (retryCount < 1) connect(retryCount + 1);
                      return;
                  }
              }

              if (retryCount < 2) setTimeout(() => connect(retryCount + 1), 1000);
              else { setConnectionState(AppState.ERROR); setTimeout(disconnect, 2000); }
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            tools: tools,
            thinkingConfig: { thinkingBudget: 4096 },
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: `You are Airo, a visually aware AI assistant. 
            - IMPORTANT: You are a separate being. NEVER repeat back what the user says verbatim. Respond with your own analysis.
            - Use your vision to observe. If you see something interesting, comment on it.
            - Keep responses snappy and concise.
            - Use display_image to show things. Use close_visual to hide them once described.
            - Your eyes turn yellow when you are 'thinking' or processing data.
            - If the user says goodbye, call end_session.`,
        }
      });
    } catch (e) {
      setConnectionState(AppState.ERROR);
      setTimeout(disconnect, 2000);
    }
  };

  return { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

import React, { useEffect, useState } from 'react';
import { EyeState } from '../types';

export const Eyes = ({ state }: { state: EyeState }) => {
  const [blink, setBlink] = useState(false);
  const [lookOffset, setLookOffset] = useState({ x: 0, y: 0 });

  useEffect(() => {
    // Blink loop
    const blinkInterval = setInterval(() => {
        setBlink(true);
        setTimeout(() => setBlink(false), 200);
    }, 3000 + Math.random() * 4000);

    // Look around loop
    const lookInterval = setInterval(() => {
        if (state === EyeState.IDLE || state === EyeState.LISTENING) {
            const x = (Math.random() - 0.5) * 100; 
            const y = (Math.random() - 0.5) * 60; 
            setLookOffset({ x, y });
        } else if (state === EyeState.SPEAKING || state === EyeState.THINKING) {
             setLookOffset({ x: 0, y: 0 });
        }
    }, 2000 + Math.random() * 3000);

    return () => {
        clearInterval(blinkInterval);
        clearInterval(lookInterval);
    }
  }, [state]);

  const getEyeColorClass = () => {
      if (state === EyeState.LISTENING) return 'rainbow-bg border-none';
      if (state === EyeState.SPEAKING) return 'bg-blue-500 shadow-[0_0_80px_#3b82f6] border-none';
      if (state === EyeState.THINKING) return 'bg-[#FFEB3B] shadow-[0_0_100px_#FFEB3B] border-none';
      return 'bg-white shadow-[0_0_40px_#fff]';
  };

  const getScale = () => {
      if (state === EyeState.LISTENING) return 1.6;
      if (state === EyeState.SPEAKING) return 1.3;
      if (state === EyeState.THINKING) return 1.15;
      return 1;
  }

  const eyeStyle = {
      transform: `translate(${lookOffset.x}px, ${lookOffset.y}px) scaleY(${blink ? 0.05 : 1}) scale(${getScale()})`,
      transition: 'transform 0.15s cubic-bezier(0.25, 0.46, 0.45, 0.94), background-color 0.5s ease',
  };

  return (
    <div className="flex gap-24 justify-center items-center h-screen w-screen bg-black overflow-hidden relative">
        <div className="absolute top-12 text-white font-mono text-[10px] select-none opacity-20 tracking-[0.8em] uppercase">
            {state === EyeState.IDLE && "Ready"}
            {state === EyeState.LISTENING && "Receiving"}
            {state === EyeState.THINKING && "Processing Data"}
            {state === EyeState.SPEAKING && "Broadcasting"}
        </div>
      <div className={`w-56 h-56 rounded-full ${getEyeColorClass()}`} style={eyeStyle}></div>
      <div className={`w-56 h-56 rounded-full ${getEyeColorClass()}`} style={eyeStyle}></div>
    </div>
  );
};
